/**
 * Analytics models for dashboard reporting.
 */

/**
 * High-level summary of platform activity.
 */
export interface AnalyticsSummary {
  totalUsers: number;
  totalOrders: number;
  revenue: number;
  activeUsers: number;
}

/**
 * Per-user analytics breakdown.
 */
export interface UserAnalytics {
  userId: string;
  orderCount: number;
  totalSpent: number;
  lastActive: Date | null;
}

/**
 * A single data point in a time-series trend.
 */
export interface TrendPoint {
  timestamp: Date;
  metric: string;
  value: number;
}

/**
 * Analytics service — aggregation and reporting logic.
 *
 * Depends on:
 * - UserRepository (data layer) for user data
 * - OrderRepository (data layer) for order data
 *
 * This service is read-only: it queries existing data to produce
 * analytics summaries, per-user breakdowns, and time-series trends.
 */

import type { AnalyticsSummary, UserAnalytics, TrendPoint } from '../models/analytics.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private userRepository: UserRepository,
    private orderRepository: OrderRepository,
  ) {}

  /**
   * Get a high-level summary of platform activity.
   */
  getSummary(): AnalyticsSummary {
    this.logger.info('Generating analytics summary');

    const users = this.userRepository.findAll();
    const orders = this.orderRepository.findAll();

    const revenue = orders.reduce((sum, order) => sum + order.total, 0);

    // Active users are those who have placed at least one order
    const userIdsWithOrders = new Set(orders.map((o) => o.userId));
    const activeUsers = userIdsWithOrders.size;

    return {
      totalUsers: users.length,
      totalOrders: orders.length,
      revenue,
      activeUsers,
    };
  }

  /**
   * Get analytics for a specific user.
   */
  getUserAnalytics(userId: string): UserAnalytics {
    this.logger.info(`Generating analytics for user: ${userId}`);

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const orders = this.orderRepository.findByUserId(userId);
    const totalSpent = orders.reduce((sum, order) => sum + order.total, 0);

    // Last active is the most recent order date, or null if no orders
    let lastActive: Date | null = null;
    if (orders.length > 0) {
      lastActive = orders.reduce(
        (latest, order) => (order.createdAt > latest ? order.createdAt : latest),
        orders[0]!.createdAt,
      );
    }

    return {
      userId,
      orderCount: orders.length,
      totalSpent,
      lastActive,
    };
  }

  /**
   * Get time-series trend data for a metric over a date range.
   *
   * Supported metrics: 'orders', 'revenue'.
   */
  getTrends(metric: string, startDate: Date, endDate: Date): TrendPoint[] {
    this.logger.info(`Generating trends for metric: ${metric}`);

    if (metric !== 'orders' && metric !== 'revenue') {
      throw new Error(`Unsupported metric: ${metric}`);
    }

    const orders = this.orderRepository.findAll(
      (order) => order.createdAt >= startDate && order.createdAt <= endDate,
    );

    // Group orders by date (day granularity)
    const buckets = new Map<string, typeof orders>();
    for (const order of orders) {
      const dayKey = order.createdAt.toISOString().split('T')[0]!;
      const bucket = buckets.get(dayKey);
      if (bucket) {
        bucket.push(order);
      } else {
        buckets.set(dayKey, [order]);
      }
    }

    // Convert buckets to trend points, sorted by date
    const points: TrendPoint[] = [];
    const sortedKeys = [...buckets.keys()].sort();

    for (const dayKey of sortedKeys) {
      const dayOrders = buckets.get(dayKey)!;
      const value =
        metric === 'orders'
          ? dayOrders.length
          : dayOrders.reduce((sum, o) => sum + o.total, 0);

      points.push({
        timestamp: new Date(dayKey),
        metric,
        value,
      });
    }

    return points;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  const makeUser = (overrides?: Partial<User>): User => ({
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date('2024-01-01'),
    updatedAt: new Date('2024-01-01'),
    ...overrides,
  });

  const makeOrder = (overrides?: Partial<Order>): Order => ({
    id: 'order-1',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    total: 20,
    status: 'pending',
    createdAt: new Date('2024-01-15'),
    updatedAt: new Date('2024-01-15'),
    ...overrides,
  });

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(userRepo, orderRepo);
  });

  describe('getSummary', () => {
    it('should return zeros when no data exists', () => {
      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(0);
      expect(summary.totalOrders).toBe(0);
      expect(summary.revenue).toBe(0);
      expect(summary.activeUsers).toBe(0);
    });

    it('should aggregate stats across users and orders', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      userRepo.save(makeUser({ id: 'user-2', name: 'Bob', email: 'bob@example.com' }));
      userRepo.save(makeUser({ id: 'user-3', name: 'Carol', email: 'carol@example.com' }));

      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 50 }));
      orderRepo.save(makeOrder({ id: 'order-2', userId: 'user-1', total: 30 }));
      orderRepo.save(makeOrder({ id: 'order-3', userId: 'user-2', total: 20 }));

      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(3);
      expect(summary.totalOrders).toBe(3);
      expect(summary.revenue).toBe(100);
      expect(summary.activeUsers).toBe(2);
    });
  });

  describe('getUserAnalytics', () => {
    it('should throw for non-existent user', () => {
      expect(() => service.getUserAnalytics('nonexistent')).toThrow('User not found');
    });

    it('should return zero stats for user with no orders', () => {
      userRepo.save(makeUser());

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.userId).toBe('user-1');
      expect(analytics.orderCount).toBe(0);
      expect(analytics.totalSpent).toBe(0);
      expect(analytics.lastActive).toBeNull();
    });

    it('should aggregate order data for a user', () => {
      userRepo.save(makeUser());

      orderRepo.save(makeOrder({
        id: 'order-1',
        total: 50,
        createdAt: new Date('2024-01-10'),
      }));
      orderRepo.save(makeOrder({
        id: 'order-2',
        total: 30,
        createdAt: new Date('2024-03-15'),
      }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.orderCount).toBe(2);
      expect(analytics.totalSpent).toBe(80);
      expect(analytics.lastActive).toEqual(new Date('2024-03-15'));
    });
  });

  describe('getTrends', () => {
    it('should throw for unsupported metric', () => {
      expect(() =>
        service.getTrends('invalid', new Date('2024-01-01'), new Date('2024-12-31')),
      ).toThrow('Unsupported metric');
    });

    it('should return empty array when no orders in range', () => {
      const trends = service.getTrends('orders', new Date('2024-01-01'), new Date('2024-12-31'));

      expect(trends).toHaveLength(0);
    });

    it('should return order count trends grouped by day', () => {
      userRepo.save(makeUser());

      orderRepo.save(makeOrder({
        id: 'order-1',
        createdAt: new Date('2024-02-01T10:00:00Z'),
      }));
      orderRepo.save(makeOrder({
        id: 'order-2',
        createdAt: new Date('2024-02-01T14:00:00Z'),
      }));
      orderRepo.save(makeOrder({
        id: 'order-3',
        createdAt: new Date('2024-02-03T09:00:00Z'),
      }));

      const trends = service.getTrends('orders', new Date('2024-01-01'), new Date('2024-12-31'));

      expect(trends).toHaveLength(2);
      expect(trends[0]?.metric).toBe('orders');
      expect(trends[0]?.value).toBe(2); // two orders on Feb 1
      expect(trends[1]?.value).toBe(1); // one order on Feb 3
    });

    it('should return revenue trends grouped by day', () => {
      userRepo.save(makeUser());

      orderRepo.save(makeOrder({
        id: 'order-1',
        total: 50,
        createdAt: new Date('2024-02-01T10:00:00Z'),
      }));
      orderRepo.save(makeOrder({
        id: 'order-2',
        total: 30,
        createdAt: new Date('2024-02-01T14:00:00Z'),
      }));

      const trends = service.getTrends('revenue', new Date('2024-01-01'), new Date('2024-12-31'));

      expect(trends).toHaveLength(1);
      expect(trends[0]?.metric).toBe('revenue');
      expect(trends[0]?.value).toBe(80);
    });

    it('should filter orders outside date range', () => {
      userRepo.save(makeUser());

      orderRepo.save(makeOrder({
        id: 'order-1',
        createdAt: new Date('2024-01-15'),
      }));
      orderRepo.save(makeOrder({
        id: 'order-2',
        createdAt: new Date('2024-06-15'),
      }));

      const trends = service.getTrends('orders', new Date('2024-01-01'), new Date('2024-03-31'));

      expect(trends).toHaveLength(1);
      expect(trends[0]?.value).toBe(1);
    });

    it('should return points sorted by date', () => {
      userRepo.save(makeUser());

      orderRepo.save(makeOrder({
        id: 'order-1',
        createdAt: new Date('2024-03-01T10:00:00Z'),
      }));
      orderRepo.save(makeOrder({
        id: 'order-2',
        createdAt: new Date('2024-01-15T10:00:00Z'),
      }));

      const trends = service.getTrends('orders', new Date('2024-01-01'), new Date('2024-12-31'));

      expect(trends).toHaveLength(2);
      expect(trends[0]!.timestamp < trends[1]!.timestamp).toBe(true);
    });
  });
});

